@code {
    private readonly string[] _stepNames = { "Personal Info", "Work History", "References", "Cover Letter", "Review & Submit" };

    private int _currentStep;
    private string _errorMessage = string.Empty;
    private bool _isValidating;
    private bool _isSubmitting;
    private bool _submitted;
    private int _applicationId;

    // Step 1 fields
    private string _fullName = string.Empty;
    private string _email = string.Empty;
    private string _phone = string.Empty;
    private string _address = string.Empty;

    // Step 2 fields
    private List<WorkEntryModel> _workEntries = new() { new WorkEntryModel() };

    // Step 3 fields
    private List<ReferenceModel> _references = new() { new ReferenceModel(), new ReferenceModel() };

    // Step 4 fields
    private string _coverLetter = string.Empty;

    private string GetStepClass(int step)
    {
        if (step == _currentStep) return "active";
        if (step < _currentStep) return "completed";
        return "future";
    }

    private void GoToStep(int step)
    {
        if (step < _currentStep)
        {
            _errorMessage = string.Empty;
            _currentStep = step;
        }
    }

    private async Task NextStep()
    {
        _errorMessage = string.Empty;

        if (!ValidateCurrentStep())
            return;

        if (_currentStep == 0)
        {
            _isValidating = true;
            try
            {
                var isValid = await ApplicationService.ValidateEmailAsync(_email);
                if (!isValid)
                {
                    _errorMessage = "Please enter a valid email address.";
                    return;
                }
            }
            finally
            {
                _isValidating = false;
            }
        }

        _currentStep++;
    }

    private void PrevStep()
    {
        _errorMessage = string.Empty;
        if (_currentStep > 0)
            _currentStep--;
    }

    private bool ValidateCurrentStep()
    {
        switch (_currentStep)
        {
            case 0:
                if (string.IsNullOrWhiteSpace(_fullName))
                { _errorMessage = "Full name is required."; return false; }
                if (string.IsNullOrWhiteSpace(_email))
                { _errorMessage = "Email is required."; return false; }
                if (string.IsNullOrWhiteSpace(_phone))
                { _errorMessage = "Phone is required."; return false; }
                if (string.IsNullOrWhiteSpace(_address))
                { _errorMessage = "Address is required."; return false; }
                return true;

            case 1:
                foreach (var entry in _workEntries)
                {
                    if (string.IsNullOrWhiteSpace(entry.Company))
                    { _errorMessage = "Company name is required for all positions."; return false; }
                    if (string.IsNullOrWhiteSpace(entry.Title))
                    { _errorMessage = "Job title is required for all positions."; return false; }
                    if (entry.StartDate == default)
                    { _errorMessage = "Start date is required for all positions."; return false; }
                    if (string.IsNullOrWhiteSpace(entry.Description))
                    { _errorMessage = "Description is required for all positions."; return false; }
                }
                return true;

            case 2:
                foreach (var reference in _references)
                {
                    if (string.IsNullOrWhiteSpace(reference.Name))
                    { _errorMessage = "Name is required for all references."; return false; }
                    if (string.IsNullOrWhiteSpace(reference.Relationship))
                    { _errorMessage = "Relationship is required for all references."; return false; }
                    if (string.IsNullOrWhiteSpace(reference.Email))
                    { _errorMessage = "Email is required for all references."; return false; }
                    if (string.IsNullOrWhiteSpace(reference.Phone))
                    { _errorMessage = "Phone is required for all references."; return false; }
                }
                return true;

            case 3:
                if (string.IsNullOrWhiteSpace(_coverLetter))
                { _errorMessage = "Cover letter is required."; return false; }
                return true;

            default:
                return true;
        }
    }

    // Work entry helpers
    private void AddWorkEntry() => _workEntries.Add(new WorkEntryModel());
    private void RemoveWorkEntry(int index) => _workEntries.RemoveAt(index);
    private void UpdateWorkEntry(int index, WorkEntryModel entry) => _workEntries[index] = entry;

    private void ToggleCurrentPosition(int index, bool isCurrent)
    {
        _workEntries[index] = _workEntries[index] with
        {
            IsCurrent = isCurrent,
            EndDate = isCurrent ? null : _workEntries[index].EndDate
        };
    }

    // Reference helpers
    private void AddReference() { if (_references.Count < 3) _references.Add(new ReferenceModel()); }
    private void RemoveReference(int index) => _references.RemoveAt(index);
    private void UpdateReference(int index, ReferenceModel reference) => _references[index] = reference;

    // Date helpers
    private static string FormatDate(DateTime date) => date == default ? string.Empty : date.ToString("yyyy-MM-dd");
    private static string FormatDate(DateTime? date) => date?.ToString("yyyy-MM-dd") ?? string.Empty;
    private static DateTime ParseDate(string? value) => DateTime.TryParse(value, out var d) ? d : default;
    private static DateTime? ParseNullableDate(string? value) => DateTime.TryParse(value, out var d) ? d : null;

    private async Task SubmitApplication()
    {
        _isSubmitting = true;
        _errorMessage = string.Empty;

        try
        {
            var application = new JobApplication(
                Personal: new PersonalInfo(_fullName, _email, _phone, _address),
                Work: new WorkHistory(_workEntries.Select(e => new WorkEntry(
                    e.Company, e.Title, e.StartDate, e.IsCurrent ? null : e.EndDate, e.Description
                )).ToList()),
                References: _references.Select(r => new Reference(r.Name, r.Relationship, r.Email, r.Phone)).ToList(),
                CoverLetter: _coverLetter
            );

            _applicationId = await ApplicationService.SubmitApplicationAsync(application);
            _submitted = true;
        }
        catch (Exception ex)
        {
            _errorMessage = $"Submission failed: {ex.Message}. Please try again.";
        }
        finally
        {
            _isSubmitting = false;
        }
    }

    private record WorkEntryModel
    {
        public string Company { get; init; } = string.Empty;
        public string Title { get; init; } = string.Empty;
        public DateTime StartDate { get; init; }
        public DateTime? EndDate { get; init; }
        public bool IsCurrent { get; init; }
        public string Description { get; init; } = string.Empty;
    }

    private record ReferenceModel
    {
        public string Name { get; init; } = string.Empty;
        public string Relationship { get; init; } = string.Empty;
        public string Email { get; init; } = string.Empty;
        public string Phone { get; init; } = string.Empty;
    }
}

