@page "/apply"
@rendermode InteractiveServer
@using sv_cb9015c840eb4e5fac5fe7a1b34775f8.Models
@using sv_cb9015c840eb4e5fac5fe7a1b34775f8.Services
@inject IApplicationService ApplicationService

<PageTitle>Job Application</PageTitle>

<div class="application-container">
    <h1>Job Application</h1>

    @if (_submitted)
    {
        <div class="confirmation">
            <div class="confirmation-icon">✓</div>
            <h2>Application Submitted!</h2>
            <p>Your application has been received. Your confirmation number is:</p>
            <div class="application-id">@_applicationId</div>
            <p>Please save this number for your records.</p>
        </div>
    }
    else
    {
        <!-- Step Indicator Bar -->
        <div class="step-indicator">
            @for (int i = 0; i < _stepNames.Length; i++)
            {
                var stepIndex = i;
                var stepClass = GetStepClass(stepIndex);
                <div class="step @stepClass" @onclick="() => GoToStep(stepIndex)">
                    <div class="step-circle">
                        @if (stepIndex < _currentStep)
                        {
                            <span>✓</span>
                        }
                        else
                        {
                            <span>@(stepIndex + 1)</span>
                        }
                    </div>
                    <div class="step-label">@_stepNames[stepIndex]</div>
                </div>
                @if (stepIndex < _stepNames.Length - 1)
                {
                    <div class="step-connector @(stepIndex < _currentStep ? "completed" : "")"></div>
                }
            }
        </div>

        @if (!string.IsNullOrEmpty(_errorMessage))
        {
            <div class="alert alert-danger mt-3">@_errorMessage</div>
        }

        <!-- Step 1: Personal Info -->
        @if (_currentStep == 0)
        {
            <div class="step-content">
                <h2>Personal Information</h2>
                <div class="form-group mb-3">
                    <label class="form-label" for="fullName">Full Name <span class="required">*</span></label>
                    <input id="fullName" class="form-control" @bind="_fullName" placeholder="Enter your full name" />
                </div>
                <div class="form-group mb-3">
                    <label class="form-label" for="email">Email <span class="required">*</span></label>
                    <input id="email" type="email" class="form-control" @bind="_email" placeholder="you@example.com" />
                </div>
                <div class="form-group mb-3">
                    <label class="form-label" for="phone">Phone <span class="required">*</span></label>
                    <input id="phone" type="tel" class="form-control" @bind="_phone" placeholder="(555) 123-4567" />
                </div>
                <div class="form-group mb-3">
                    <label class="form-label" for="address">Address <span class="required">*</span></label>
                    <textarea id="address" class="form-control" @bind="_address" rows="2" placeholder="Enter your address"></textarea>
                </div>
                <div class="step-buttons">
                    <div></div>
                    <button class="btn btn-primary" @onclick="NextStep" disabled="@_isValidating">
                        @if (_isValidating)
                        {
                            <span class="spinner-border spinner-border-sm me-1"></span>
                            <span>Validating...</span>
                        }
                        else
                        {
                            <span>Next →</span>
                        }
                    </button>
                </div>
            </div>
        }

        <!-- Step 2: Work History -->
        @if (_currentStep == 1)
        {
            <div class="step-content">
                <h2>Work History</h2>
                @for (int i = 0; i < _workEntries.Count; i++)
                {
                    var index = i;
                    <div class="work-entry-card">
                        <div class="work-entry-header">
                            <h4>Position @(index + 1)</h4>
                            @if (_workEntries.Count > 1)
                            {
                                <button class="btn btn-outline-danger btn-sm" @onclick="() => RemoveWorkEntry(index)">Remove</button>
                            }
                        </div>
                        <div class="row">
                            <div class="col-md-6 mb-3">
                                <label class="form-label">Company Name <span class="required">*</span></label>
                                <input class="form-control" value="@_workEntries[index].Company"
                                       @onchange="(e) => UpdateWorkEntry(index, _workEntries[index] with { Company = e.Value?.ToString() ?? string.Empty })" />
                            </div>
                            <div class="col-md-6 mb-3">
                                <label class="form-label">Job Title <span class="required">*</span></label>
                                <input class="form-control" value="@_workEntries[index].Title"
                                       @onchange="(e) => UpdateWorkEntry(index, _workEntries[index] with { Title = e.Value?.ToString() ?? string.Empty })" />
                            </div>
                        </div>
                        <div class="row">
                            <div class="col-md-4 mb-3">
                                <label class="form-label">Start Date <span class="required">*</span></label>
                                <input type="date" class="form-control" value="@FormatDate(_workEntries[index].StartDate)"
                                       @onchange="(e) => UpdateWorkEntry(index, _workEntries[index] with { StartDate = ParseDate(e.Value?.ToString()) })" />
                            </div>
                            <div class="col-md-4 mb-3">
                                <label class="form-label">End Date</label>
                                <input type="date" class="form-control" value="@FormatDate(_workEntries[index].EndDate)"
                                       disabled="@_workEntries[index].IsCurrent"
                                       @onchange="(e) => UpdateWorkEntry(index, _workEntries[index] with { EndDate = ParseNullableDate(e.Value?.ToString()) })" />
                            </div>
                            <div class="col-md-4 mb-3 d-flex align-items-end">
                                <div class="form-check">
                                    <input type="checkbox" class="form-check-input" id="current-@index" checked="@_workEntries[index].IsCurrent"
                                           @onchange="(e) => ToggleCurrentPosition(index, (bool)(e.Value ?? false))" />
                                    <label class="form-check-label" for="current-@index">Currently working here</label>
                                </div>
                            </div>
                        </div>
                        <div class="mb-3">
                            <label class="form-label">Description <span class="required">*</span></label>
                            <textarea class="form-control" rows="3" value="@_workEntries[index].Description"
                                      @onchange="(e) => UpdateWorkEntry(index, _workEntries[index] with { Description = e.Value?.ToString() ?? string.Empty })"></textarea>
                        </div>
                    </div>
                }
                <button class="btn btn-outline-secondary mb-3" @onclick="AddWorkEntry">+ Add Another Position</button>
                <div class="step-buttons">
                    <button class="btn btn-secondary" @onclick="PrevStep">← Back</button>
                    <button class="btn btn-primary" @onclick="NextStep">Next →</button>
                </div>
            </div>
        }

        <!-- Step 3: References -->
        @if (_currentStep == 2)
        {
            <div class="step-content">
                <h2>References</h2>
                @for (int i = 0; i < _references.Count; i++)
                {
                    var index = i;
                    <div class="reference-card">
                        <div class="work-entry-header">
                            <h4>Reference @(index + 1)</h4>
                            @if (_references.Count > 2)
                            {
                                <button class="btn btn-outline-danger btn-sm" @onclick="() => RemoveReference(index)">Remove</button>
                            }
                        </div>
                        <div class="row">
                            <div class="col-md-6 mb-3">
                                <label class="form-label">Name <span class="required">*</span></label>
                                <input class="form-control" value="@_references[index].Name"
                                       @onchange="(e) => UpdateReference(index, _references[index] with { Name = e.Value?.ToString() ?? string.Empty })" />
                            </div>
                            <div class="col-md-6 mb-3">
                                <label class="form-label">Relationship <span class="required">*</span></label>
                                <input class="form-control" value="@_references[index].Relationship"
                                       @onchange="(e) => UpdateReference(index, _references[index] with { Relationship = e.Value?.ToString() ?? string.Empty })" />
                            </div>
                        </div>
                        <div class="row">
                            <div class="col-md-6 mb-3">
                                <label class="form-label">Email <span class="required">*</span></label>
                                <input type="email" class="form-control" value="@_references[index].Email"
                                       @onchange="(e) => UpdateReference(index, _references[index] with { Email = e.Value?.ToString() ?? string.Empty })" />
                            </div>
                            <div class="col-md-6 mb-3">
                                <label class="form-label">Phone <span class="required">*</span></label>
                                <input type="tel" class="form-control" value="@_references[index].Phone"
                                       @onchange="(e) => UpdateReference(index, _references[index] with { Phone = e.Value?.ToString() ?? string.Empty })" />
                            </div>
                        </div>
                    </div>
                }
                @if (_references.Count < 3)
                {
                    <button class="btn btn-outline-secondary mb-3" @onclick="AddReference">+ Add Reference</button>
                }
                <div class="step-buttons">
                    <button class="btn btn-secondary" @onclick="PrevStep">← Back</button>
                    <button class="btn btn-primary" @onclick="NextStep">Next →</button>
                </div>
            </div>
        }

        <!-- Step 4: Cover Letter -->
        @if (_currentStep == 3)
        {
            <div class="step-content">
                <h2>Cover Letter</h2>
                <div class="mb-3">
                    <label class="form-label">Write your cover letter below</label>
                    <textarea class="form-control cover-letter-textarea" rows="12" maxlength="2000"
                              @bind="_coverLetter" @bind:event="oninput"
                              placeholder="Tell us why you're a great fit for this position..."></textarea>
                    <div class="character-count @(_coverLetter.Length > 1800 ? "warning" : "")">
                        @_coverLetter.Length / 2000 characters
                    </div>
                </div>
                <div class="step-buttons">
                    <button class="btn btn-secondary" @onclick="PrevStep">← Back</button>
                    <button class="btn btn-primary" @onclick="NextStep">Next →</button>
                </div>
            </div>
        }

        <!-- Step 5: Review & Submit -->
        @if (_currentStep == 4)
        {
            <div class="step-content">
                <h2>Review & Submit</h2>

                <div class="review-section">
                    <div class="review-header">
                        <h4>Personal Information</h4>
                        <button class="btn btn-link btn-sm" @onclick="() => GoToStep(0)">Edit</button>
                    </div>
                    <div class="review-grid">
                        <div><strong>Name:</strong> @_fullName</div>
                        <div><strong>Email:</strong> @_email</div>
                        <div><strong>Phone:</strong> @_phone</div>
                        <div><strong>Address:</strong> @_address</div>
                    </div>
                </div>

                <div class="review-section">
                    <div class="review-header">
                        <h4>Work History</h4>
                        <button class="btn btn-link btn-sm" @onclick="() => GoToStep(1)">Edit</button>
                    </div>
                    @foreach (var entry in _workEntries)
                    {
                        <div class="review-work-entry">
                            <strong>@entry.Title</strong> at @entry.Company<br />
                            <span class="text-muted">
                                @entry.StartDate.ToString("MMM yyyy") —
                                @(entry.IsCurrent ? "Present" : entry.EndDate?.ToString("MMM yyyy") ?? "N/A")
                            </span>
                            <p class="mt-1 mb-0">@entry.Description</p>
                        </div>
                    }
                </div>

                <div class="review-section">
                    <div class="review-header">
                        <h4>References</h4>
                        <button class="btn btn-link btn-sm" @onclick="() => GoToStep(2)">Edit</button>
                    </div>
                    @foreach (var reference in _references)
                    {
                        <div class="review-reference">
                            <strong>@reference.Name</strong> — @reference.Relationship<br />
                            <span class="text-muted">@reference.Email · @reference.Phone</span>
                        </div>
                    }
                </div>

                <div class="review-section">
                    <div class="review-header">
                        <h4>Cover Letter</h4>
                        <button class="btn btn-link btn-sm" @onclick="() => GoToStep(3)">Edit</button>
                    </div>
                    <div class="review-cover-letter">@_coverLetter</div>
                </div>

                <div class="step-buttons">
                    <button class="btn btn-secondary" @onclick="PrevStep">← Back</button>
                    <button class="btn btn-success btn-lg" @onclick="SubmitApplication" disabled="@_isSubmitting">
                        @if (_isSubmitting)
                        {
                            <span class="spinner-border spinner-border-sm me-1"></span>
                            <span>Submitting...</span>
                        }
                        else
                        {
                            <span>Submit Application</span>
                        }
                    </button>
                </div>
            </div>
        }
    }
</div>

@code {
    private readonly string[] _stepNames = { "Personal Info", "Work History", "References", "Cover Letter", "Review & Submit" };

    private int _currentStep;
    private string _errorMessage = string.Empty;
    private bool _isValidating;
    private bool _isSubmitting;
    private bool _submitted;
    private int _applicationId;

    // Step 1 fields
    private string _fullName = string.Empty;
    private string _email = string.Empty;
    private string _phone = string.Empty;
    private string _address = string.Empty;

    // Step 2 fields
    private List<WorkEntryModel> _workEntries = new() { new WorkEntryModel() };

    // Step 3 fields
    private List<ReferenceModel> _references = new() { new ReferenceModel(), new ReferenceModel() };

    // Step 4 fields
    private string _coverLetter = string.Empty;

    private string GetStepClass(int step)
    {
        if (step == _currentStep) return "active";
        if (step < _currentStep) return "completed";
        return "future";
    }

    private void GoToStep(int step)
    {
        if (step < _currentStep)
        {
            _errorMessage = string.Empty;
            _currentStep = step;
        }
    }

    private async Task NextStep()
    {
        _errorMessage = string.Empty;

        if (!ValidateCurrentStep())
            return;

        if (_currentStep == 0)
        {
            _isValidating = true;
            try
            {
                var isValid = await ApplicationService.ValidateEmailAsync(_email);
                if (!isValid)
                {
                    _errorMessage = "Please enter a valid email address.";
                    return;
                }
            }
            finally
            {
                _isValidating = false;
            }
        }

        _currentStep++;
    }

    private void PrevStep()
    {
        _errorMessage = string.Empty;
        if (_currentStep > 0)
            _currentStep--;
    }

