arguments.file_text:
.application-container {
    max-width: 800px;
    margin: 0 auto;
    padding: 2rem 1rem;
}

.application-container h1 {
    text-align: center;
    margin-bottom: 2rem;
    color: #333;
}

/* Step Indicator */
.step-indicator {
    display: flex;
    align-items: center;
    justify-content: center;
    margin-bottom: 2rem;
    flex-wrap: wrap;
    gap: 0;
}

.step {
    display: flex;
    flex-direction: column;
    align-items: center;
    cursor: default;
    min-width: 90px;
}

.step.completed {
    cursor: pointer;
}

.step-circle {
    width: 36px;
    height: 36px;
    border-radius: 50%;
    display: flex;
    align-items: center;
    justify-content: center;
    font-weight: 600;
    font-size: 0.9rem;
    border: 2px solid #dee2e6;
    background: #fff;
    color: #adb5bd;
    transition: all 0.2s;
}

.step.active .step-circle {
    border-color: #0d6efd;
    background: #0d6efd;
    color: #fff;
}

.step.completed .step-circle {
    border-color: #198754;
    background: #198754;
    color: #fff;
}

.step-label {
    margin-top: 0.35rem;
    font-size: 0.75rem;
    color: #adb5bd;
    text-align: center;
    white-space: nowrap;
}

.step.active .step-label {
    color: #0d6efd;
    font-weight: 600;
}

.step.completed .step-label {
    color: #198754;
}

.step-connector {
    flex: 1;
    height: 2px;
    background: #dee2e6;
    min-width: 20px;
    max-width: 60px;
    margin: 0 0.25rem;
    align-self: flex-start;
    margin-top: 18px;
    transition: background 0.2s;
}

.step-connector.completed {
    background: #198754;
}

/* Step Content */
.step-content {
    background: #fff;
    border: 1px solid #dee2e6;
    border-radius: 8px;
    padding: 2rem;
}

.step-content h2 {
    margin-bottom: 1.5rem;
    color: #333;
    border-bottom: 2px solid #f0f0f0;
    padding-bottom: 0.75rem;
}

.required {
    color: #dc3545;
}

.step-buttons {
    display: flex;
    justify-content: space-between;
